35	    public func read() async -> UsagesFile {
36	        do {
37	            return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
38	        } catch is CancellationError {
39	            return UsagesFile()
40	        } catch {
41	            logger.log(.warning, "flock read failed — returning empty file: \(error)")
42	            return UsagesFile()
