47	        await update(with: entries, outagesByVendor: [:])
48	    }
49	
50	    /// Applies a usage merge plus per-vendor outage replacement in a single locked read-modify-write.
51	    ///
52	    /// Outage policy per vendor key in `outagesByVendor`:
53	    /// - present, non-empty list → replaces all outages of that vendor
54	    /// - present, empty list → removes all outages of that vendor ("all clear")
55	    /// - absent → outages of that vendor are preserved as-is (fetch failed, or no connector for it)
56	    public func update(
57	        with entries: [VendorUsageEntry],
58	        outagesByVendor: [Vendor: [Outage]]
59	    ) async {
