123	    // MARK: - Outage replacement
124	
125	    /// Replaces outages per-vendor while preserving outages for vendors absent from `replacements`.
126	    /// Vendors not covered by a status connector (or producers external to this app) keep their
127	    /// entries untouched, so the file format stays open to multiple producers.
128	    func applyOutageReplacement(
129	        existing: [Outage],
130	        replacements: [Vendor: [Outage]]
131	    ) -> [Outage] {
132	        var result = existing.filter { replacements[$0.vendor] == nil }
133	        for (_, newOutages) in replacements {
134	            result.append(contentsOf: newOutages)
135	        }
136	        return result
137	    }
138	
139	    // MARK: - Merge logic
140	
141	    func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
142	        // Usage entries are vendor-keyed upserts; outages are handled separately by
143	        // `applyOutageReplacement`, which the public `update(with:outagesByVendor:)` runs
144	        // after this merge. The file format is open to external outage producers for
145	        // vendors without a status connector.
146	        let vendorsWithResolvedAccounts = Set(
147	            incoming
148	                .filter { !Self.isAccountUnknownPlaceholder($0) }
149	                .map(\.vendor)
150	        )
151	        var usages = existing.usages.filter { entry in
152	            !(vendorsWithResolvedAccounts.contains(entry.vendor) && Self.isAccountUnknownPlaceholder(entry))
153	        }
154	        var indexByKey: [String: Int] = [:]
155	        for (i, entry) in usages.enumerated() {
156	            indexByKey["\(entry.vendor.rawValue)|\(entry.account.rawValue)"] = i
157	        }
158	        for entry in incoming {
159	            guard !Self.isAccountUnknownPlaceholder(entry) else {
160	                continue
161	            }
162	            let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
163	            if let idx = indexByKey[key] {
164	                if entry.lastError != nil {
165	                    // Errors must not erase previously acquired data: the file may hold good
166	                    // metrics from a prior successful fetch while the connector's in-memory
167	                    // lastKnownMetrics is empty (e.g. after an app restart).
168	                    var merged = entry
169	                    if merged.metrics.isEmpty {
170	                        merged.metrics = usages[idx].metrics
171	                    }
172	                    if merged.lastAcquiredOn == nil {
173	                        merged.lastAcquiredOn = usages[idx].lastAcquiredOn
174	                    }
175	                    usages[idx] = merged
176	                } else {
177	                    usages[idx] = entry
178	                }
179	            } else {
180	                indexByKey[key] = usages.count
181	                usages.append(entry)
182	            }
183	        }
184	
185	        return UsagesFile(usages: usages, outages: existing.outages)
186	    }
187	
188	    private static func isAccountUnknownPlaceholder(_ entry: VendorUsageEntry) -> Bool {
189	        entry.account.rawValue == "unknown" && entry.lastError?.type == "account_unknown"
190	    }
