192	    // MARK: - Lock-guarded internals
193	
194	    /// Acquires an advisory flock on the dedicated lock file, runs `body`, then releases.
195	    /// Uses a separate lock file because atomic writes replace the JSON inode, making
196	    /// flock on the data file itself ineffective for protecting external readers.
197	    private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
198	        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
199	        guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
200	        defer { Darwin.close(fd) }
201	
202	        let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
203	        while flock(fd, mode | LOCK_NB) != 0 {
204	            guard Date() < deadline else {
205	                throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
206	            }
207	            try await Task.sleep(for: .milliseconds(50))
208	        }
209	        defer { flock(fd, LOCK_UN) }
210	
211	        return try body()
212	    }
213	
214	    // MARK: - Unsafe (actor-isolated, no external lock needed)
215	
216	    private func readUnsafe() -> UsagesFile {
217	        guard let data = FileManager.default.contents(atPath: filePath) else {
218	            return UsagesFile()
219	        }
220	        do {
221	            return try JSONDecoder().decode(UsagesFile.self, from: data)
222	        } catch {
223	            logger.log(.error, "Failed to decode \(filePath): \(error)")
224	            return UsagesFile()
225	        }
226	    }
227	
228	    private func writeUnsafe(_ file: UsagesFile) {
229	        let encoder = JSONEncoder()
230	        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
231	        guard let data = try? encoder.encode(file) else {
232	            logger.log(.error, "Failed to encode usages file")
233	            return
234	        }
235	        do {
236	            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
237	        } catch {
238	            logger.log(.error, "Atomic write failed: \(error)")
239	            return
240	        }
241	        logger.log(.debug, "Wrote usages file to \(filePath)")
242	    }
243	}
