246	    case cannotOpenLockFile(path: String)
247	    case lockTimeout(path: String, timeoutSeconds: Double)
248	
249	    var description: String {
250	        switch self {
251	        case let .cannotOpenLockFile(path):
252	            "Cannot open lock file at \(path)"
253	        case let .lockTimeout(path, secs):
254	            "Could not acquire flock on \(path) within \(secs)s"
255	        }
